import React, { useEffect, useRef, useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  SafeAreaView,
  StyleSheet,
  ActivityIndicator,
  Platform,
  Dimensions,
  Animated,
  TextInput,
  Modal,
  ScrollView,
  Pressable,
} from 'react-native';

export const { width: SCREEN_WIDTH } = Dimensions.get('window');

// ─── DESIGN TOKENS ─────────────────────────────────────────────────────────────
// Professional dark-navy palette — serious, trustworthy, emergency-grade
export const Colors = {
  // Brand
  primary:     '#C0392B',   // Deep emergency red
  primaryDark: '#96281B',
  primaryLight:'#E74C3C',

  // Accent
  accent:      '#2980B9',   // Strong blue
  accentDark:  '#1A5276',
  accentLight: '#3498DB',

  // Status
  danger:      '#C0392B',
  warning:     '#E67E22',
  warningDark: '#A04000',
  success:     '#1E8449',
  successLight:'#27AE60',
  info:        '#2471A3',

  // Navy scale (background)
  navy900:     '#0A0F1E',
  navy800:     '#0D1526',
  navy700:     '#111C30',
  navy600:     '#162038',
  navy500:     '#1C2944',

  // Neutral
  white:       '#FFFFFF',
  offWhite:    '#F8F9FA',
  gray50:      '#F2F3F4',
  gray100:     '#E5E8EC',
  gray200:     '#CBD0D8',
  gray300:     '#A9B1BD',
  gray400:     '#7F8C9A',
  gray500:     '#5D6B7A',
  gray600:     '#445060',
  gray700:     '#2E3D4F',
  gray800:     '#1C2A3A',
  gray900:     '#0E1B29',

  // Legacy aliases (keep compatibility with existing screens)
  red:         '#C0392B',
  redDark:     '#96281B',
  orange:      '#E67E22',
  orangeDark:  '#A04000',
  blue:        '#2980B9',
  blueDark:    '#1A5276',
  purple:      '#7D3C98',
  purpleDark:  '#5B2C6F',
  teal:        '#148F77',
  tealDark:    '#0E6655',
  slate:       '#5D6D7E',
  slateDark:   '#2E4053',
  green:       '#1E8449',
  greenDark:   '#145A32',
  amber:       '#E67E22',
  amberDark:   '#A04000',
};

// ─── SAFE AREA CONTAINER ───────────────────────────────────────────────────────
interface SafeAreaContainerProps { children: React.ReactNode; style?: any; }
export const SafeAreaContainer: React.FC<SafeAreaContainerProps> = ({ children, style }) => (
  <SafeAreaView style={[styles.safeContainer, style]}>{children}</SafeAreaView>
);

// ─── HEADER ───────────────────────────────────────────────────────────────────
interface HeaderProps {
  title: string;
  onBack?: () => void;
  rightAction?: React.ReactNode;
  color?: string;
  dark?: boolean;
}
export const Header: React.FC<HeaderProps> = ({ title, onBack, rightAction, color, dark }) => {
  const isDark = dark || !!color;
  const bg = color ?? (dark ? Colors.navy800 : Colors.white);
  const textColor = isDark ? Colors.white : Colors.gray900;
  const borderColor = isDark ? 'transparent' : Colors.gray100;
  return (
    <View style={[styles.header, { backgroundColor: bg, borderBottomColor: borderColor }]}>
