// ─── GOLDEN HOUR TIMER ─────────────────────────────────────────────────────────
interface GoldenHourTimerProps { startTime: number; }
export const GoldenHourTimer: React.FC<GoldenHourTimerProps> = ({ startTime }) => {
  const pulse = useRef(new Animated.Value(1)).current;
  const [remaining, setRemaining] = useState(3600);
  useEffect(() => {
    const interval = setInterval(() => {
      const elapsed = Math.floor((Date.now() - startTime) / 1000);
      setRemaining(Math.max(0, 3600 - elapsed));
    }, 1000);
    return () => clearInterval(interval);
  }, [startTime]);
  useEffect(() => {
    if (remaining <= 1800) {
      const anim = Animated.loop(
        Animated.sequence([
          Animated.timing(pulse, { toValue: 1.02, duration: 500, useNativeDriver: true }),
          Animated.timing(pulse, { toValue: 1, duration: 500, useNativeDriver: true }),
        ])
      );
      anim.start();
      return () => anim.stop();
    }
  }, [remaining <= 1800]);
  const mins = Math.floor(remaining / 60).toString().padStart(2, '0');
  const secs = (remaining % 60).toString().padStart(2, '0');
  const isUrgent = remaining <= 1800;
  return (
    <Animated.View style={[styles.goldenTimer, { backgroundColor: isUrgent ? Colors.primaryDark : Colors.primary, transform: [{ scale: pulse }] }]}>
      <View>
        <Text style={styles.goldenTimerLabel}>GOLDEN HOUR</Text>
        <Text style={styles.goldenTimerSub}>Time-sensitive window for survival</Text>
      </View>
      <Text style={styles.goldenTimerTime}>{mins}:{secs}</Text>
    </Animated.View>
  );
};

