// ─── KM MARKER MODAL ──────────────────────────────────────────────────────────
interface KmMarkerModalProps { visible: boolean; onClose: () => void; onResolve: (highway: string, km: string) => void; }
export const KmMarkerModal: React.FC<KmMarkerModalProps> = ({ visible, onClose, onResolve }) => {
  const [highway, setHighway] = useState('');
  const [km, setKm] = useState('');
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [resolved, setResolved] = useState<any>(null);
  const slideAnim = useRef(new Animated.Value(300)).current;

  let getHighwayList: () => string[] = () => [];
  let resolveKmMarker: (h: string, k: number) => any = () => null;
  try {
    const db = require('../services/emergencyDB');
    getHighwayList = db.getHighwayList;
    resolveKmMarker = db.resolveKmMarker;
  } catch {}
  const allHighways = getHighwayList();

  useEffect(() => {
    if (visible) {
      setHighway(''); setKm(''); setResolved(null); setSuggestions([]);
      Animated.spring(slideAnim, { toValue: 0, useNativeDriver: true, tension: 80, friction: 12 }).start();
    } else { slideAnim.setValue(300); }
  }, [visible]);

  const handleHighwayChange = (text: string) => {
    setHighway(text); setResolved(null);
    if (text.length >= 2) {
      const q = text.toUpperCase().replace(/\s/g, '');
      setSuggestions(allHighways.filter((h) => h.replace(/[\s-]/g, '').toUpperCase().includes(q)).slice(0, 5));
    } else { setSuggestions([]); }
  };

  const handleFind = () => {
    if (!highway || !km) return;
    const result = resolveKmMarker(highway, parseInt(km));
    if (result) { setResolved(result); } else { onResolve(highway, km); }
  };

  return (
    <Modal visible={visible} transparent animationType="none" onRequestClose={onClose}>
      <Pressable style={styles.modalOverlay} onPress={onClose}>
        <Animated.View style={[styles.modalSheet, { transform: [{ translateY: slideAnim }] }]}>
          <Pressable>
            <View style={styles.modalHandle} />
            <Text style={styles.modalTitle}>HIGHWAY KM MARKER</Text>
            <Text style={styles.modalSubtitle}>For emergencies where GPS address is unclear</Text>

            <Text style={styles.inputLabel}>HIGHWAY</Text>
            <TextInput
              style={styles.modalInput} placeholder="e.g. NH-48" value={highway}
              onChangeText={handleHighwayChange} placeholderTextColor={Colors.gray400}
              autoCapitalize="characters"
            />
            {suggestions.length > 0 && (
              <View style={styles.suggestBox}>
                {suggestions.map((s) => (
                  <TouchableOpacity key={s} style={styles.suggestItem} onPress={() => { setHighway(s); setSuggestions([]); }}>
                    <Text style={styles.suggestText}>{s}</Text>
                  </TouchableOpacity>
                ))}
              </View>
            )}

            <Text style={styles.inputLabel}>KM NUMBER</Text>
            <TextInput
              style={styles.modalInput} placeholder="e.g. 142" value={km}
              onChangeText={setKm} keyboardType="numeric" placeholderTextColor={Colors.gray400}
            />

            {resolved && (
              <View style={styles.resolvedCard}>
                <Text style={styles.resolvedTitle}>Location confirmed in offline database</Text>
                <Text style={styles.resolvedSub}>{resolved.highway}, KM {resolved.km} · {resolved.state}</Text>
                {resolved.nearbyHospital && <Text style={styles.resolvedSub}>Hospital: {resolved.nearbyHospital}</Text>}
                {resolved.nearbyPump && <Text style={styles.resolvedSub}>Fuel: {resolved.nearbyPump}</Text>}
              </View>
            )}

            <TouchableOpacity
              style={[styles.modalBtn, (!highway || !km) && { opacity: 0.5 }]}
              onPress={resolved ? () => onResolve(highway, km) : handleFind}
              disabled={!highway || !km}
            >
              <Text style={styles.modalBtnText}>{resolved ? 'Use This Location' : 'Look Up Services'}</Text>
            </TouchableOpacity>
            <TouchableOpacity style={styles.modalCancelBtn} onPress={onClose}>
              <Text style={styles.modalCancelText}>Cancel</Text>
            </TouchableOpacity>
          </Pressable>
        </Animated.View>
      </Pressable>
    </Modal>
  );
};

